import React, { useState } from 'react';
import { Button, Select, addToast } from '@linm-soft/common-components';
import { useAppDispatch } from '../../store/hooks';
import { MONTH_OPTIONS, yearOptions } from '../../constants/voucher';
import { getApiErrorMessage } from '../../utils/getApiErrorMessage';
import df from '../../styles/documentForm.module.css';

export interface PeriodActionPanelProps {
  title: string;
  icon: string;
  description?: string;
  testIdPrefix?: string;
  showMonth?: boolean;
  runLabel?: string;
  postLabel?: string;
  onRun: (month: number, year: number) => Promise<unknown>;
  onPost?: (month: number, year: number) => Promise<unknown>;
}

export const PeriodActionPanel: React.FC<PeriodActionPanelProps> = ({
  title,
  icon,
  description,
  testIdPrefix = 'kt-period-action',
  showMonth = true,
  runLabel = 'Thực hiện',
  postLabel = 'Ghi sổ',
  onRun,
  onPost,
}) => {
  const dispatch = useAppDispatch();
  const now = new Date();
  const [month, setMonth] = useState(String(now.getMonth() + 1));
  const [year, setYear] = useState(String(now.getFullYear()));
  const [running, setRunning] = useState(false);
  const [posting, setPosting] = useState(false);

  const m = Number(month);
  const y = Number(year);

  const handleRun = async () => {
    setRunning(true);
    try {
      await onRun(m, y);
      dispatch(addToast({ message: `${runLabel} thành công`, type: 'success' }));
    } catch (e: unknown) {
      dispatch(addToast({
        message: getApiErrorMessage(e, `${runLabel} thất bại`),
        type: 'error',
      }));
    } finally {
      setRunning(false);
    }
  };

  const handlePost = async () => {
    if (!onPost) return;
    setPosting(true);
    try {
      await onPost(m, y);
      dispatch(addToast({ message: `${postLabel} thành công`, type: 'success' }));
    } catch (e: unknown) {
      dispatch(addToast({ message: getApiErrorMessage(e, `${postLabel} thất bại`), type: 'error' }));
    } finally {
      setPosting(false);
    }
  };

  const tid = (suffix: string) => `${testIdPrefix}-${suffix}`;

  return (
    <div className={df.page} data-testid={tid('page')}>
      <div className={df.stickyTop}>
        <div className={df.pageHeader}>
          <div className={df.titleGroup}>
            <div>
              <div className={df.titleRow}>
                <h1 className={df.title} data-testid={tid('title')}>
                  <i className={`fas ${icon}`} style={{ marginRight: 8 }} />
                  {title}
                </h1>
              </div>
              {description && (
                <p style={{ margin: '4px 0 0', fontSize: 13, color: 'var(--color-text-secondary, #6c757d)' }}>
                  {description}
                </p>
              )}
            </div>
          </div>
        </div>
      </div>

      <div className={df.section} data-testid={tid('section-period')}>
        <h2 className={df.sectionTitle}>Kỳ thực hiện</h2>
        <div className={df.row4}>
          {showMonth && (
            <div className={df.field} data-testid={tid('field-month')}>
              <label className={df.label}>Tháng</label>
              <Select value={month} onChange={e => setMonth(e.target.value)} options={MONTH_OPTIONS} />
            </div>
          )}
          <div className={df.field} data-testid={tid('field-year')}>
            <label className={df.label}>Năm</label>
            <Select value={year} onChange={e => setYear(e.target.value)} options={yearOptions()} />
          </div>
          <div className={df.field} aria-hidden />
          <div className={df.field} aria-hidden />
        </div>
        <div className={df.footer} style={{ marginTop: 12, padding: 0, border: 'none', background: 'transparent' }}>
          <Button variant="primary" data-testid={tid('run-btn')} onClick={handleRun} loading={running}>{runLabel}</Button>
          {onPost && <Button variant="secondary" data-testid={tid('post-btn')} onClick={handlePost} loading={posting}>{postLabel}</Button>}
        </div>
      </div>
    </div>
  );
};
